import React from 'react';

/**
 * AdminModal — saisie du mot de passe administrateur.
 * Le contrôle effectif (validation, ouverture/fermeture) est délégué au
 * MODULE 7 (ADMIN) du fichier `core/portfolio.js`.
 */
const AdminModal = () => (
  <div id="admin-modal" className="modal-overlay" style={{ display: 'none' }}>
    <div className="modal-box">
      <div className="modal-icon">🔐</div>
      <div className="modal-title">Accès administrateur</div>
      <div className="modal-sub">Entrez votre mot de passe pour activer le mode édition.</div>
      <input
        type="password"
        className="modal-input"
        id="admin-pwd"
        placeholder="••••••••"
        onKeyDown={(e) => { if (e.key === 'Enter' && window.checkAdmin) window.checkAdmin(); }}
      />
      <div className="modal-err" id="admin-err" />
      <div className="modal-btns">
        <button className="modal-btn cancel" onClick={() => window.closeAdminModal && window.closeAdminModal()}>Annuler</button>
        <button className="modal-btn confirm" onClick={() => window.checkAdmin && window.checkAdmin()}>Confirmer</button>
      </div>
    </div>
  </div>
);

export default AdminModal;
