import React, { useEffect } from 'react';

// ───── Layout ─────
import Navbar from './components/layout/Navbar';
import Footer from './components/layout/Footer';
import SectionNav from './components/layout/SectionNav';
import BackToTop from './components/layout/BackToTop';

// ───── Sections ─────
import Hero from './components/sections/Hero';
import About from './components/sections/About';
import Experience from './components/sections/Experience';
import Skills from './components/sections/Skills';
import Projects from './components/sections/Projects';
import Education from './components/sections/Education';
import Contact from './components/sections/Contact';

// ───── Overlays / Modals ─────
import AdminModal from './components/overlays/AdminModal';
import EditModal from './components/overlays/EditModal';
import ConfirmModal from './components/overlays/ConfirmModal';
import Lightbox from './components/overlays/Lightbox';
import ColorPanel from './components/overlays/ColorPanel';
import GlobalUtilities from './components/overlays/GlobalUtilities';

// ───── Cœur applicatif (logique métier vanilla, modulaire) ─────
import { initPortfolio } from './core/portfolio';

// ───── Styles globaux du portfolio ─────
import './styles/portfolio.css';

/**
 * App — composant racine du portfolio.
 *
 * Architecture :
 * ──────────────
 *   1. Le rendu JSX (ci-dessous) reproduit fidèlement la structure DOM
 *      attendue par le moteur logique (`core/portfolio.js`). Chaque section
 *      est isolée dans son propre composant pour faciliter la lecture.
 *   2. Au montage du composant, `initPortfolio()` est exécuté **une seule
 *      fois** afin d'initialiser : chargement des données, rendu dynamique
 *      des sections, listeners (scroll, drag & drop, événements admin…).
 *
 * Ce découpage offre la lisibilité d'une architecture React modulaire tout
 * en préservant à 100 % le comportement de l'application monopage initiale.
 */
const App = () => {
  useEffect(() => {
    initPortfolio();
  }, []);

  return (
    <div id="body-root">
      {/* Curseur custom + barre de progression du scroll */}
      <div id="cursor" />
      <div id="scroll-progress" />

      <Navbar />

      <Hero />
      <About />
      <Projects />
      <Experience />
      <Skills />
      <Education />
      <Contact />

      <Footer />

      <SectionNav />
      <BackToTop />

      {/* Overlays globaux */}
      <AdminModal />
      <EditModal />
      <Lightbox />
      <ConfirmModal />
      <ColorPanel />
      <GlobalUtilities />
    </div>
  );
};

export default App;
