import React, { useState, useEffect } from 'react';
import { Moon, Palette, Menu, X } from 'lucide-react';

/**
 * Navbar — barre de navigation principale.
 * - Logique métier (langue/thème/PDF/admin) gérée par core/portfolio.js via window.*
 * - Menu hamburger mobile géré localement (state React).
 */
const Navbar = () => {
  const [open, setOpen] = useState(false);
  // Ferme le menu lors d'un clic sur un lien
  useEffect(() => {
    const ul = document.getElementById('nav-links');
    if (!ul) return;
    const handler = (e) => { if (e.target.tagName === 'A') setOpen(false); };
    ul.addEventListener('click', handler);
    return () => ul.removeEventListener('click', handler);
  }, []);

  return (
    <nav id="navbar" className={open ? 'open' : ''}>
      <a href="#hero" className="nav-logo" id="nav-logo-text" data-testid="nav-logo">
        AED<span>.dev</span>
      </a>

      <ul className="nav-links" id="nav-links" data-testid="nav-links">
        <li><a href="#about" data-fr="À propos" data-en="About">À propos</a></li>
        <li><a href="#projects" data-fr="Projets" data-en="Projects">Projets</a></li>
        <li><a href="#experience" data-fr="Expérience" data-en="Experience">Expérience</a></li>
        <li><a href="#skills" data-fr="Compétences" data-en="Skills">Compétences</a></li>
        <li><a href="#education" data-fr="Formation" data-en="Education">Formation</a></li>
        <li><a href="#contact" data-fr="Contact" data-en="Contact">Contact</a></li>
      </ul>

      <div className="nav-right">
        <a
          className="nav-pdf nav-cv"
          id="nav-cv-btn"
          href="Elisabeth_Dorkenoo_CV_FR.pdf"
          download
          data-fr="📄 CV"
          data-en="📄 Resume"
          data-cv-fr="Elisabeth_Dorkenoo_CV_FR.pdf"
          data-cv-en="Elisabeth_Dorkenoo_CV_EN.pdf"
          title="Télécharger le CV au format PDF"
          data-testid="nav-cv-btn"
        >📄 CV</a>
        <div className="lang-toggle" role="group" aria-label="Langue">
          <button className="lang-btn active" id="btn-fr" onClick={() => window.setLang && window.setLang('fr')} data-testid="lang-fr">FR</button>
          <button className="lang-btn" id="btn-en" onClick={() => window.setLang && window.setLang('en')} data-testid="lang-en">EN</button>
        </div>
        <button className="theme-btn" id="theme-btn" onClick={() => window.toggleTheme && window.toggleTheme()} title="Changer le thème" aria-label="Changer le thème" data-testid="theme-toggle">
          <Moon size={16} aria-hidden="true" />
        </button>
        <button className="theme-btn" id="palette-btn" onClick={() => window.openColorPanel && window.openColorPanel()} title="Personnaliser les couleurs" aria-label="Personnaliser les couleurs" style={{ display: 'none' }}>
          <Palette size={16} aria-hidden="true" />
        </button>
        <button
          className="nav-burger"
          type="button"
          aria-label={open ? 'Fermer le menu' : 'Ouvrir le menu'}
          aria-expanded={open}
          aria-controls="nav-links"
          onClick={() => setOpen((v) => !v)}
          data-testid="nav-burger-btn"
        >
          {open ? <X size={20} aria-hidden="true" /> : <Menu size={20} aria-hidden="true" />}
        </button>
        <button
          className="admin-btn"
          id="admin-btn"
          onClick={() => window.toggleAdmin && window.toggleAdmin()}
          aria-hidden="true"
          tabIndex={-1}
          style={{ background: 'transparent', borderColor: 'transparent', color: 'transparent', boxShadow: 'none', opacity: 0, pointerEvents: 'auto' }}
        />
      </div>
    </nav>
  );
};

export default Navbar;
