import React from 'react';

/**
 * EditModal — modale générique d'édition.
 * Le contenu (titre, corps, callback de sauvegarde) est injecté dynamiquement
 * par `openEditModal()` (cf. MODULE 8 dans `core/portfolio.js`).
 */
const EditModal = () => (
  <div id="edit-modal" className="modal-overlay" style={{ display: 'none' }}>
    <div className="modal-box" style={{ width: 520, maxWidth: '95vw' }}>
      <div className="modal-title" id="edit-modal-title">Modifier</div>
      <div className="edit-form" id="edit-modal-body" />
      <div className="modal-btns" style={{ marginTop: 20 }}>
        <button className="modal-btn cancel" onClick={() => window.closeEditModal && window.closeEditModal()}>Annuler</button>
        <button className="modal-btn confirm" id="edit-modal-save">Enregistrer</button>
      </div>
    </div>
  </div>
);

export default EditModal;
