function t(obj, key) { return obj[key+'_'+lang] || obj[key+'_fr'] || ''; }

// ── SECTIONS CONFIG ──
// Toutes les sections optionnelles (excluant hero, about, contact qui sont toujours visibles)
var OPTIONAL_SECTIONS = [
  {id:'projects',        fr:'Projets',          en:'Projects'},
  {id:'experience',      fr:'Expérience',       en:'Experience'},
  {id:'skills',          fr:'Compétences',      en:'Skills'},
  {id:'education',       fr:'Formation',        en:'Education'},
  {id:'certifications',  fr:'Certifications',   en:'Certifications'},
  {id:'interests',       fr:"Centres d'intérêt", en:'Interests'},
  {id:'references',      fr:'Références',       en:'References'},
  {id:'blog',            fr:'Blog & Articles',  en:'Blog & Articles'},
];

// Map section id → clé du tableau de données
var SECTION_DATA_KEY = {
  projects:       'projects',
  experience:     'experience',
  skills:         'skills',
  education:      'education',
  certifications: 'certifications',
  interests:      'interests',
  references:     'references',
  blog:           'blog',
};

function hasContent(id) {
  var key = SECTION_DATA_KEY[id];
  if (!key) return true; // sections sans data (about, contact, hero) toujours considérées remplies
  var arr = D[key];
  return Array.isArray(arr) && arr.length > 0;
}

function isSectionVisible(id) {
  // Cachée manuellement via mode admin ?
  if (D.hidden_sections && D.hidden_sections.indexOf(id) !== -1) return false;
  // Auto-cacher les sections optionnelles vides
  return hasContent(id);
}

function renderNavLinks() {

// ════════════════════════════════════════════════════════════
// MODULE 5 ─ SECTIONS : Visibilité & navigation
// ════════════════════════════════════════════════════════════
  var ALL_NAV = [
    {id:'about',          fr:'À propos',     en:'About'},
    {id:'projects',       fr:'Projets',      en:'Projects'},
    {id:'experience',     fr:'Expérience',   en:'Experience'},
    {id:'skills',         fr:'Compétences',  en:'Skills'},
    {id:'education',      fr:'Formation',    en:'Education'},
    {id:'certifications', fr:'Certifications', en:'Certifications'},
    {id:'interests',      fr:'Intérêts',     en:'Interests'},
    {id:'references',     fr:'Références',   en:'References'},
    {id:'blog',           fr:'Blog',         en:'Blog'},
    {id:'contact',        fr:'Contact',      en:'Contact'},
  ];
  var ul = document.getElementById('nav-links');
  if(!ul) return;
  ul.innerHTML = ALL_NAV
    .filter(function(s) { return isSectionVisible(s.id); })
    .map(function(s) {
      return '<li><a href="#'+s.id+'" data-fr="'+s.fr+'" data-en="'+s.en+'">'+(lang==='fr'?s.fr:s.en)+'</a></li>';
    }).join('');
  // Réduire la taille de police si trop de liens
  var count = ul.querySelectorAll('li').length;
  ul.style.fontSize = count > 7 ? '.58rem' : count > 5 ? '.63rem' : '.65rem';
}

function applyVisibility() {
  OPTIONAL_SECTIONS.forEach(function(s) {
    var el = document.getElementById(s.id);
    if(el) el.style.display = isSectionVisible(s.id) ? '' : 'none';
    // mini-nav
    var snav = document.querySelector('.snav-item[data-target="'+s.id+'"]');
    if(snav) snav.style.display = isSectionVisible(s.id) ? '' : 'none';
    // navbar
    var navLink = document.querySelector('.nav-links a[href="#'+s.id+'"]');
    if(navLink && navLink.parentElement) navLink.parentElement.style.display = isSectionVisible(s.id) ? '' : 'none';
  });
  updateSectionNumbers();
  renderNavLinks();
}

function updateSectionNumbers() {
  // Recalculer les numéros selon les sections visibles (ordre Hero → About → Projects → ...)
  var visibleOrder = ['about','projects','experience','skills','education','certifications','interests','references','blog','contact'];
  var num = 1;
  visibleOrder.forEach(function(id) {
    if(id === 'contact') {
      var cel = document.querySelector('#contact .section-num');
      if(cel) { cel.textContent = String(num).padStart(2,'0'); }
      return;
    }
    var sec = document.getElementById(id);
    if(!sec || sec.style.display === 'none') return;
    var numEl = sec.querySelector('.section-num');
    if(numEl) numEl.textContent = String(num).padStart(2,'0');
    num++;
  });
}

function openSectionsManager() {
  var body = '<div style="padding:4px 0"><p style="font-size:.82rem;color:var(--text3);margin-bottom:16px">'+
    (lang==='fr' ? 'Cochez les sections à afficher sur votre portfolio :' : 'Check the sections to show on your portfolio:')+
    '</p>';
  OPTIONAL_SECTIONS.forEach(function(s) {
    var checked = isSectionVisible(s.id);
    body += '<label style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;background:var(--bg3);margin-bottom:6px;cursor:none">'+
      '<input type="checkbox" id="sec-vis-'+s.id+'" '+(checked?'checked':'')+' style="accent-color:var(--cyan3);width:16px;height:16px"/>'+
      '<span style="font-family:DM Sans,sans-serif;font-size:.88rem;color:var(--text)">'+(lang==='fr'?s.fr:s.en)+'</span>'+
      '</label>';
  });
  body += '</div>';
  openEditModal(lang==='fr' ? 'Gérer les sections' : 'Manage sections', body, function() {
    D.hidden_sections = [];
    OPTIONAL_SECTIONS.forEach(function(s) {
      var cb = document.getElementById('sec-vis-'+s.id);
      if(cb && !cb.checked) D.hidden_sections.push(s.id);
    });
    saveData();
    applyVisibility();
  });
}


function extractStartYear(dateStr) {
  if(!dateStr) return 0;
  var m = dateStr.match(/(\d{4})/);
  return m ? parseInt(m[1]) : 0;
}
function sortByDateDesc(arr) {
  return arr.slice().sort(function(a,b) {
    var da = extractStartYear(a.dates || a.years || '');
    var db = extractStartYear(b.dates || b.years || '');
    return db - da;
  });
}

