      var btn = document.createElement('button');
      btn.id = 'hero-admin-btn';
      btn.className = 'admin-edit-btn';
      btn.setAttribute('data-action','editMeta');
      btn.textContent = '✏️ Modifier le profil';
      btn.style.cssText = 'position:absolute;top:16px;right:16px;z-index:10';
      document.getElementById('hero').style.position = 'relative';
