function markdownToHtml(md) {
  if(!md) return '';
  var html = md;
  html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
  html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/`([^`]+)`/g, '<code>$1</code>');
  html = html.replace(/((?:^- .+$\n?)+)/gm, function(block) {
    var items = block.trim().split('\n').map(function(l){ return '<li>'+l.replace(/^- /,'')+'</li>'; }).join('');
    return '<ul>'+items+'</ul>';
  });
  html = html.split('\n\n').map(function(block) {
    if(block.trim().startsWith('<')) return block;
    return '<p>'+block.replace(/\n/g,' ')+'</p>';
  }).join('');
  return html;
}
function renderProjects() {
  const pg = document.getElementById('projects-grid');
  const STATUS_LABELS = {
    livre:    {fr:'Livré',     en:'Shipped',     cls:'status-shipped'},
    encours:  {fr:'En cours',  en:'In progress', cls:'status-progress'},
    archive:  {fr:'Archivé',   en:'Archived',    cls:'status-archived'},
  };
  function projectCardHtml(p, i) {
    const imgs = p.images || [];
    const readmeHtml = t(p,'readme') || '';
    const sections = p.sections || [];
    const thumbs = imgs.slice(0,3).map((img,ii) =>
      `<img class="project-img-thumb" src="${img}" data-action="openLightbox" data-proj="${i}" data-idx="${ii}"/>`
    ).join('');
    const moreCount = imgs.length > 3 ? `<div class="project-img-count">+${imgs.length-3}</div>` : '';
    const preview = imgs.length > 0
      ? `<img src="${imgs[0]}" alt="${p.name}" style="width:100%;height:100%;object-fit:cover;position:absolute;inset:0" data-action="openLightbox" data-proj="${i}" data-idx="0"/>`
      : `<div class="project-preview-band" aria-hidden="true"></div>`;
    const role = t(p,'role');
    const metaParts = [];
    if(role) metaParts.push(`<span class="project-meta-item"><span class="meta-key">${lang==='fr'?'Rôle':'Role'}</span> ${role}</span>`);
    if(p.year) metaParts.push(`<span class="project-meta-item"><span class="meta-key">${lang==='fr'?'Année':'Year'}</span> ${p.year}</span>`);
    if(p.status && STATUS_LABELS[p.status]) {
      const st = STATUS_LABELS[p.status];
      metaParts.push(`<span class="project-status ${st.cls}">${lang==='fr'?st.fr:st.en}</span>`);
    }
    const metaHtml = metaParts.length ? `<div class="project-meta">${metaParts.join('')}</div>` : '';
    const sectionsHtml = sections.length ? `<div class="project-sections">${sections.map(function(sec){
      var ttl = (lang==='fr'?sec.title_fr:sec.title_en) || sec.title_fr || sec.title_en || '';
      var ct = (lang==='fr'?sec.content_html_fr:sec.content_html_en) || sec.content_html_fr || sec.content_html_en || '';
      return '<div class="project-subsection"><div class="subsection-title">'+ttl+'</div><div class="subsection-content">'+ct+'</div></div>';
    }).join('')}</div>` : '';
    return `
    <div class="project-card${p.featured?' featured':''} reveal" style="position:relative" draggable="${isAdmin}" data-i="${i}">
      <div class="project-preview">
        <div class="project-preview-bg"></div>
        ${preview}
      </div>
      <div class="project-info">
        ${isAdmin?`<button class="admin-delete-btn" data-action="deleteProject" data-i="${i}" style="position:absolute;top:8px;right:8px">🗑</button>`:''}
        <div class="project-type">${t(p,'type')}</div>
        <div class="project-name">${p.name}</div>
        ${metaHtml}
        ${imgs.length > 0 ? `<div class="project-images">${thumbs}${moreCount}</div>` : ''}
        ${readmeHtml
          ? `<div class="project-readme project-readme-collapsed" id="readme-${i}">${readmeHtml}</div><button class="readme-toggle" data-action="toggleReadme" data-i="${i}">${lang==='fr'?'Lire plus ↓':'Read more ↓'}</button>`
          : `<div class="project-desc">${t(p,'desc')}</div>`}
        ${sectionsHtml}
        <div class="project-stack">${p.tags.map(tg=>`<span class="stack-tag">${tg}</span>`).join('')}</div>
        ${(p.url_github||p.url_demo) ? `<div class="project-links">
          ${p.url_github?`<a class="project-link github" href="${normalizeUrl(p.url_github)}" target="_blank" rel="noopener">⬡ GitHub</a>`:''}
          ${p.url_demo?`<a class="project-link demo" href="${normalizeUrl(p.url_demo)}" target="_blank" rel="noopener">↗ ${lang==='fr'?'Voir la démo':'Live demo'}</a>`:''}
        </div>`:''}
        ${isAdmin?`<button class="admin-edit-btn" data-action="editProject" data-i="${i}">✏️ Modifier</button>`:''}
      </div>
    </div>`;
  }
  // Index global pour conserver l'index réel des projets dans D.projects (drag/edit)
  var indexed = D.projects.map(function(p, i){ return {p: p, i: i}; });
  var webGroup  = indexed.filter(function(x){ return (x.p.category||'web') !== 'data'; });
  var dataGroup = indexed.filter(function(x){ return (x.p.category||'web') === 'data'; });

  var pgWeb = document.getElementById('projects-grid-web');
  var pgData = document.getElementById('projects-grid-data');

  // Rendu dans les deux carrousels distincts
  if(pgWeb)  pgWeb.innerHTML  = webGroup.map(function(x){ return projectCardHtml(x.p, x.i); }).join('');
  if(pgData) pgData.innerHTML = dataGroup.map(function(x){ return projectCardHtml(x.p, x.i); }).join('');

  // Masquer la sous-section si vide
  var webBlock = document.getElementById('projects-web-block');
  var dataBlock = document.getElementById('projects-data-block');
  if(webBlock)  webBlock.style.display  = webGroup.length  ? '' : 'none';
  if(dataBlock) dataBlock.style.display = dataGroup.length ? '' : 'none';

  // Compat ascendante : si un ancien conteneur 'projects-grid' existe encore, on le vide
  var legacyPg = document.getElementById('projects-grid');
  if(legacyPg && legacyPg !== pgWeb && legacyPg !== pgData) legacyPg.innerHTML = '';
}

