function getContactHref(ct) {
  var key = (ct.key_fr||ct.key_en||'').toLowerCase();
  var val = ct.val||'';
  if(key.includes('email') || key.includes('mail') || val.includes('@')) return 'mailto:'+val;
  if(key.includes('tel') || key.includes('phone') || key.includes('portable') || key.includes('mobile')) return 'tel:'+val.replace(/\s/g,'');
  if(key.includes('linkedin') || val.includes('linkedin.com')) return normalizeUrl(val);
  if(key.includes('github') || val.includes('github.com')) return normalizeUrl(val);
  if(val.startsWith('http')||val.startsWith('www')) return normalizeUrl(val);
  return null;
}

