function toggleAdmin() {
  if(isAdmin) { exitAdmin(); return; }
  document.getElementById('admin-modal').style.display = 'flex';
  setTimeout(()=>document.getElementById('admin-pwd').focus(),100);
}
function closeAdminModal() {
  document.getElementById('admin-modal').style.display = 'none';
  document.getElementById('admin-pwd').value = '';
  document.getElementById('admin-err').textContent = '';
}
// SHA-256 du mot de passe admin par défaut, **avec sel** (`ADMIN_SALT|password`).
// Le sel n'est pas un secret (il est dans le bundle public), mais il invalide les
// rainbow tables génériques : un attaquant doit construire une table dédiée à ce sel.
// Combiné au coût de SHA-256 par tentative dans le navigateur, c'est suffisant
// pour bloquer un curieux et ralentir une vraie attaque par force brute.
// ⚠️ Reste : un portfolio statique n'a pas de backend pour vérifier un token ;
// cette protection ne remplace pas une vraie authentification.
// Pour changer : `echo -n "portfolio-static-2026|MonNouveauPwd" | sha256sum`
//                puis remplace la valeur de ADMIN_PWD_SHA256 ci-dessous.
var ADMIN_SALT = 'portfolio-static-2026';
var ADMIN_PWD_SHA256 = '2b3776a223e4aede6019da3f305fc3c0ef06a477098e0b580cbad6daae06be1b';

async function sha256Hex(str) {
  var enc = new TextEncoder().encode(str);
  var buf = await crypto.subtle.digest('SHA-256', enc);
  return Array.from(new Uint8Array(buf))
    .map(function(b){ return b.toString(16).padStart(2,'0'); })
    .join('');
}

async function checkAdmin() {
  var pwdInput = document.getElementById('admin-pwd');
  var errEl = document.getElementById('admin-err');
  if(!pwdInput || !errEl) return;
  try {
    var hash = await sha256Hex(ADMIN_SALT + '|' + pwdInput.value);
    if(hash === ADMIN_PWD_SHA256) {
      isAdmin = true; closeAdminModal(); enterAdmin();
    } else {
      errEl.textContent = 'Mot de passe incorrect.';
      pwdInput.value = '';
    }
  } catch(e) {
    errEl.textContent = 'Erreur de vérification (Web Crypto indisponible).';
  }
}
function exportHTML() {
  var html = document.documentElement.outerHTML;
  var scriptTag = '<scr'+'ipt>var EXPORT_DATA=' + JSON.stringify(D) + ';<'+'/scr'+'ipt>';
  html = html.replace('<'+'/head>', scriptTag + '<'+'/head>');
  var blob = new Blob([html], {type: 'text/html;charset=utf-8'});
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'portfolio_export_' + new Date().toISOString().slice(0,10) + '.html';
  a.click();
  URL.revokeObjectURL(a.href);
}

// Export en `defaultData.js` prêt à coller dans `frontend/src/data/defaultData.js`.
// Workflow GitHub Pages : édite visuellement ➜ clique ➜ remplace le fichier ➜ git push.
function exportDefaultDataJS() {
  // Copie des données courantes en retirant les champs purement runtime
  var data = JSON.parse(JSON.stringify(D));
  // Sérialisation lisible (indentation 2 espaces)
  var json = JSON.stringify(data, null, 2);
  var header = '/**\n' +
    ' * ============================================================================\n' +
    ' *  defaultData.js — Données par défaut du portfolio\n' +
    ' * ============================================================================\n' +
    ' *  Fichier généré automatiquement depuis le mode admin\n' +
    ' *  (' + new Date().toISOString() + ')\n' +
    ' *\n' +
    ' *  Workflow GitHub Pages :\n' +
    ' *    1. Remplace `frontend/src/data/defaultData.js` par ce fichier.\n' +
    ' *    2. `git add frontend/src/data/defaultData.js && git commit -m "update content"`\n' +
    ' *    3. `git push origin main` ➜ GitHub Actions redéploie le site.\n' +
    ' *    4. Le recruteur voit immédiatement les nouvelles données.\n' +
    ' * ============================================================================\n' +
    ' */\n\n' +
    'export const DEFAULT_DATA = ';
  var footer = ';\n';
  var content = header + json + footer;
  var blob = new Blob([content], {type: 'application/javascript;charset=utf-8'});
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'defaultData.js';
  a.click();
  URL.revokeObjectURL(a.href);
}
// Comparaison structurelle profonde, indépendante de l'ordre des clés.
// Plus robuste qu'un `JSON.stringify(a) === JSON.stringify(b)` qui peut donner
// des faux positifs si deux objets sérialisent leurs propriétés dans un ordre
// différent (cas possible après JSON.parse / spread / merge selon le moteur JS).
function deepEqual(a, b) {
  if(a === b) return true;
  if(typeof a !== typeof b) return false;
  if(a === null || b === null) return a === b;
  if(typeof a !== 'object') return a === b;
  if(Array.isArray(a) !== Array.isArray(b)) return false;
  if(Array.isArray(a)) {
    if(a.length !== b.length) return false;
    for(var i=0; i<a.length; i++) { if(!deepEqual(a[i], b[i])) return false; }
    return true;
  }
  var ka = Object.keys(a), kb = Object.keys(b);
  if(ka.length !== kb.length) return false;
  for(var j=0; j<ka.length; j++) {
    var k = ka[j];
    if(!Object.prototype.hasOwnProperty.call(b, k)) return false;
    if(!deepEqual(a[k], b[k])) return false;
  }
  return true;
}
// Détecte si les données courantes diffèrent de DEFAULT_DATA (= "modifs non publiées")
function hasUnpublishedChanges() {
  try { return !deepEqual(D, DEFAULT_DATA); } catch(e) { return false; }
}
// Met à jour le badge "•" sur le bouton Publier en fonction de l'état dirty
function refreshPublishBadge() {
  var btn = document.getElementById('export-data-btn');
  if(!btn) return;
  if(hasUnpublishedChanges()) {
    btn.classList.add('has-changes');
    btn.textContent = '📤 Publier';
    btn.title = "⚠️ Modifications locales non publiées.\n\nPour les rendre visibles par le recruteur :\n1. Clique ici → télécharge defaultData.js\n2. Remplace frontend/src/data/defaultData.js dans ton repo\n3. git commit && git push → GitHub Actions redéploie\n4. ✅ Le recruteur voit tes modifs";
  } else {
    btn.classList.remove('has-changes');
    btn.textContent = '📤 Publier';
    btn.title = "Aucune modification locale à publier.\n(Tes données = celles de defaultData.js)";
  }
}

