function richEditor(name, html, placeholder) {
  return '<div class="edit-field">' +
    '<label class="edit-label">' + (name==='readme-fr'?'Description longue FR':'Description longue EN') + '</label>' +
    '<div class="rich-editor-wrap">' +
      '<div class="rich-toolbar" id="tb-'+name+'">' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'bold\')" title="Gras"><strong>B</strong></button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'italic\')" title="Italique"><em>I</em></button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'underline\')" title="Souligné"><u>U</u></button>' +
        '<div class="tb-sep"></div>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'h1\')" title="Titre 1">H1</button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'h2\')" title="Titre 2">H2</button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'h3\')" title="Titre 3">H3</button>' +
        '<div class="tb-sep"></div>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'ul\')" title="Liste à puces">• Liste</button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'ol\')" title="Liste numérotée">1. Liste</button>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'check\')" title="Case à cocher">☑ Case</button>' +
        '<div class="tb-sep"></div>' +
        '<button onmousedown="event.preventDefault();richCmd(\'' + name + '\',\'code\')" title="Code">{ }</button>' +
      '</div>' +
      '<div class="rich-content" id="rich-'+name+'" contenteditable="true" data-placeholder="'+placeholder+'">' + html + '</div>' +
    '</div>' +
  '</div>';
}

function richCmd(name, cmd) {
  var el = document.getElementById('rich-'+name);
  if(!el) return;
  el.focus();
  if(cmd==='bold') document.execCommand('bold');
  else if(cmd==='italic') document.execCommand('italic');
  else if(cmd==='underline') document.execCommand('underline');
  else if(cmd==='h1') document.execCommand('formatBlock', false, 'h1');
  else if(cmd==='h2') document.execCommand('formatBlock', false, 'h2');
  else if(cmd==='h3') document.execCommand('formatBlock', false, 'h3');
  else if(cmd==='ul') document.execCommand('insertUnorderedList');
  else if(cmd==='ol') document.execCommand('insertOrderedList');
  else if(cmd==='code') {
    var sel = window.getSelection();
    if(sel && sel.toString()) {
      var code = document.createElement('code');
      var range = sel.getRangeAt(0);
      range.surroundContents(code);
    }
  } else if(cmd==='check') {
    var cb = document.createElement('input');
    cb.type = 'checkbox';
    var lbl = document.createElement('label');
    lbl.appendChild(cb);
    lbl.appendChild(document.createTextNode(' '));
    document.execCommand('insertHTML', false, '<label><input type="checkbox"/> </label><br/>');
  }
}

