// LIGHTBOX plein écran
let _lbImages = [], _lbIdx = 0;

// ════════════════════════════════════════════════════════════
// MODULE 10 ─ LIGHTBOX & MODALS : Visionneuse & PDF
// ════════════════════════════════════════════════════════════
function openLightbox(images, idx) {
  if(!images || !images.length) return;
  _lbImages = images; _lbIdx = idx;
  updateLightbox();
  document.getElementById('lightbox').classList.add('open');
}
function closeLightbox() { document.getElementById('lightbox').classList.remove('open'); }
function updateLightbox() {
  document.getElementById('lightbox-img').src = _lbImages[_lbIdx];
  document.getElementById('lightbox-caption').textContent = (_lbIdx+1) + ' / ' + _lbImages.length;
  var dots = document.getElementById('lightbox-dots');
  dots.innerHTML = _lbImages.map(function(_,i){ return '<button class="lb-dot'+(i===_lbIdx?' active':'')+'" data-li="'+i+'"></button>'; }).join('');
  dots.querySelectorAll('.lb-dot').forEach(function(d){ d.addEventListener('click', function(){ _lbIdx=parseInt(d.dataset.li); updateLightbox(); }); });
  document.getElementById('lb-prev').disabled = _lbIdx === 0;
  document.getElementById('lb-next').disabled = _lbIdx === _lbImages.length - 1;
}
document.getElementById('lb-prev').addEventListener('click', function(){ if(_lbIdx>0){_lbIdx--;updateLightbox();} });
document.getElementById('lb-next').addEventListener('click', function(){ if(_lbIdx<_lbImages.length-1){_lbIdx++;updateLightbox();} });
document.getElementById('lightbox').addEventListener('click', function(e){ if(e.target.id==='lightbox'||e.target.id==='lightbox-img-wrap') closeLightbox(); });
// Blog modal close
document.getElementById('blog-modal-close').addEventListener('click', function(){ document.getElementById('blog-modal-overlay').classList.remove('open'); });
document.getElementById('blog-modal-overlay').addEventListener('click', function(e){ if(e.target.id==='blog-modal-overlay') document.getElementById('blog-modal-overlay').classList.remove('open'); });
document.addEventListener('keydown', function(e){ if(e.key==='Escape') document.getElementById('blog-modal-overlay').classList.remove('open'); });
document.addEventListener('keydown', function(e) {
  if(document.getElementById('lightbox').classList.contains('open')) {
    if(e.key==='ArrowLeft' && _lbIdx>0){_lbIdx--;updateLightbox();}
    if(e.key==='ArrowRight' && _lbIdx<_lbImages.length-1){_lbIdx++;updateLightbox();}
    if(e.key==='Escape') closeLightbox();
  }
  if(document.getElementById('cert-modal').classList.contains('open') && e.key==='Escape') closeCertModal();
});

