var DEFAULT_COLORS = {
  dark: {
    accent:  '#06b0cc',   // cyan principal (--cyan3)
    accentD: '#0580a0',   // cyan foncé (--cyan4)
    bg0:     '#060d14',   // fond page
    bg2:     '#0f1e2d',   // fond cards
  },
  light: {
    accent:  '#0069aa',
    accentD: '#004f88',
    bg0:     '#cdd9e7',
    bg2:     '#d7e3f6',
  }
};

var customColors = JSON.parse(localStorage.getItem('portfolio_colors') || 'null') || {
  dark:  Object.assign({}, DEFAULT_COLORS.dark),
  light: Object.assign({}, DEFAULT_COLORS.light)
};

function hexToRgb(hex) {
  var r = parseInt(hex.slice(1,3),16), g = parseInt(hex.slice(3,5),16), b = parseInt(hex.slice(5,7),16);
  return r+','+g+','+b;
}

function lighten(hex, amt) {
  // amt: 0-255 à ajouter à chaque canal
  var r = Math.min(255, parseInt(hex.slice(1,3),16)+amt);
  var g = Math.min(255, parseInt(hex.slice(3,5),16)+amt);
  var b = Math.min(255, parseInt(hex.slice(5,7),16)+amt);
  return '#'+[r,g,b].map(x=>x.toString(16).padStart(2,'0')).join('');
}
function darken(hex, amt) { return lighten(hex, -amt); }

function applyCustomColors(theme) {
  var col = customColors[theme];
  var root = document.documentElement;
  var pfx = theme === 'light' ? '[data-theme="light"]' : '';
  // On injecte via un style tag dédié
  var tag = document.getElementById('custom-color-style');
  if(!tag) { tag = document.createElement('style'); tag.id='custom-color-style'; document.head.appendChild(tag); }
  
  var darkVars = theme === 'dark' ? ':root' : '[data-theme="light"]';
  // Calculer bg1..bg5 automatiquement depuis bg0 et bg2
  var b0 = col.bg0, b2 = col.bg2;
  var b1 = lighten(b0, 10);
  var b3 = darken(b2, 12);
  var b4 = darken(b2, 22);
  var b5 = darken(b2, 32);

  tag.textContent = (tag.textContent || '').replace(
    new RegExp('/\*'+theme+'\*/[\s\S]*?/\*end'+theme+'\*/','g'), ''
  );
  tag.textContent += '/*'+theme+'*/'+darkVars+'{'+
    '--bg0:'+b0+';--bg1:'+b1+';--bg2:'+b2+';--bg3:'+b3+';--bg4:'+b4+';--bg5:'+b5+';'+
    '--cyan3:'+col.accent+';--cyan4:'+col.accentD+';'+
    '--grad:linear-gradient(135deg,'+col.accent+','+lighten(col.accent,20)+');'+
    '--glow:0 8px 32px rgba('+hexToRgb(col.accent)+',.2);'+
    '--glow2:0 16px 48px rgba('+hexToRgb(col.accent)+',.3);'+
  '}/*end'+theme+'*/';
}

function saveCustomColors() {
  localStorage.setItem('portfolio_colors', JSON.stringify(customColors));
  applyCustomColors('dark');
  applyCustomColors('light');
}

function resetColors(theme) {
  customColors[theme] = Object.assign({}, DEFAULT_COLORS[theme]);
  saveCustomColors();
  renderColorPanel();
}

