// FORM SUBMIT — double fallback : Web3Forms (principal) → FormSubmit (secours) → mailto:
// Si l'un des deux services est en panne, l'autre prend automatiquement le relais.
// Aucun message perdu, le visiteur ne voit que "Message envoyé ✓".
async function trySendWeb3Forms(payload) {
  if(!D.web3forms_access_key) throw new Error('No Web3Forms key');
  // FormData = "simple request" => pas de preflight CORS => marche sur tout domaine
  const fd = new FormData();
  fd.append('access_key', D.web3forms_access_key);
  fd.append('name', payload.name);
  fd.append('email', payload.email);
  fd.append('message', payload.message);
  fd.append('subject', payload.subject);
  fd.append('from_name', 'Portfolio — ' + payload.name);
  const resp = await fetch('https://api.web3forms.com/submit', {
    method: 'POST',
    body: fd
  });
  const data = await resp.json().catch(() => ({}));
  if(!resp.ok || data.success !== true) throw new Error(data.message || 'Web3Forms error');
  return true;
}

async function trySendFormSubmit(payload) {
  if(!D.contact_email) throw new Error('No FormSubmit email');
  const resp = await fetch('https://formsubmit.co/ajax/' + D.contact_email, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: JSON.stringify({
      name: payload.name,
      email: payload.email,
      message: payload.message,
      _subject: payload.subject,
      _template: 'table',
      _captcha: 'false'
    })
  });
  const data = await resp.json().catch(() => ({}));
  if(!resp.ok || (data.success !== 'true' && data.success !== true)) {
    throw new Error(data.message || 'FormSubmit error');
  }
  return true;
}

document.getElementById('form-submit').addEventListener('click', async () => {
  const nameEl = document.getElementById('form-name');
  const emailEl = document.getElementById('form-email');
  const msgEl   = document.getElementById('form-msg');
  const name = nameEl.value.trim();
  const email = emailEl.value.trim();
  const msg = msgEl.value.trim();
  if(!name||!email||!msg) {
    alert(lang==='fr'?'Veuillez remplir tous les champs.':'Please fill in all fields.');
    return;
  }
  const btn = document.getElementById('form-submit');
  const orig = btn.textContent;
  btn.disabled = true;
  btn.textContent = lang==='fr' ? 'Envoi en cours…' : 'Sending…';

  const payload = {
    name: name,
    email: email,
    message: msg,
    subject: (lang==='fr'?'Contact portfolio — ':'Portfolio contact — ') + name
  };

  let sent = false;
  // 1) Tentative Web3Forms (service principal)
  try {
    await trySendWeb3Forms(payload);
    sent = true;
  } catch(e1) {
    console.warn('Web3Forms KO, fallback FormSubmit:', e1 && e1.message);
    // 2) Fallback FormSubmit
    try {
      await trySendFormSubmit(payload);
      sent = true;
    } catch(e2) {
      console.warn('FormSubmit KO aussi:', e2 && e2.message);
    }
  }

  if(sent) {
    btn.textContent = lang==='fr' ? 'Message envoyé ✓' : 'Message sent ✓';
    btn.style.background = 'linear-gradient(135deg,#22c55e,#16a34a)';
    nameEl.value = ''; emailEl.value = ''; msgEl.value = '';
  } else {
    // 3) Dernier recours : ouverture du client mail local
    const sub = encodeURIComponent(payload.subject);
    const body = encodeURIComponent((lang==='fr'?'De : ':'From: ') + name + ' (' + email + ')\n\n' + msg);
    window.location.href = 'mailto:' + (D.contact_email || D.web3forms_email) + '?subject=' + sub + '&body=' + body;
    btn.textContent = lang==='fr' ? 'Ouverture mail…' : 'Opening mail…';
  }

  setTimeout(function(){
    btn.textContent = orig;
    btn.style.background = '';
    btn.disabled = false;
  }, 3500);
});

