var _dragState = { containerId: null, dragIdx: null };

var DRAG_CONTAINERS = {};

// ════════════════════════════════════════════════════════════
// MODULE 13 ─ DRAG & DROP : Glisser-déposer
// ════════════════════════════════════════════════════════════

function initDrag(containerId, dataArr, renderFn) {
  DRAG_CONTAINERS[containerId] = { arr: dataArr, fn: renderFn };
}

function initGlobalDrag() {
  document.addEventListener('dragstart', function(e) {
    if(!isAdmin) return;
    // Ignorer les drag-handle eux-mêmes, prendre le parent draggable
    var el = e.target.closest('[draggable="true"][data-i]');
    if(!el || el.getAttribute('draggable') !== 'true') return;
    var containerId = null;
    for(var cid in DRAG_CONTAINERS) {
      var cont = document.getElementById(cid);
      if(cont && cont.contains(el)) { containerId = cid; break; }
    }
    if(!containerId) return;
    _dragState.containerId = containerId;
    _dragState.dragIdx = parseInt(el.getAttribute('data-i'));
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', _dragState.dragIdx);
    setTimeout(function(){ el.classList.add('dragging'); }, 0);
  });

  document.addEventListener('dragend', function(e) {
    document.querySelectorAll('.dragging').forEach(function(x){ x.classList.remove('dragging'); });
    document.querySelectorAll('.drag-over').forEach(function(x){ x.classList.remove('drag-over'); });
  });

  document.addEventListener('dragover', function(e) {
    if(_dragState.dragIdx === null) return;
    var el = e.target.closest('[draggable="true"][data-i]');
    if(!el) return;
    var cont = document.getElementById(_dragState.containerId);
    if(!cont || !cont.contains(el)) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    document.querySelectorAll('.drag-over').forEach(function(x){ x.classList.remove('drag-over'); });
    el.classList.add('drag-over');
  });

  document.addEventListener('drop', function(e) {
    e.preventDefault();
    var cid = _dragState.containerId;
    var fromIdx = _dragState.dragIdx;
    // Reset état immédiatement
    _dragState.containerId = null;
    _dragState.dragIdx = null;
    document.querySelectorAll('.dragging,.drag-over').forEach(function(x){
      x.classList.remove('dragging'); x.classList.remove('drag-over');
    });
    if(!cid || fromIdx === null) return;
    var el = e.target.closest('[draggable="true"][data-i]');
    if(!el) return;
    var cont = document.getElementById(cid);
    if(!cont || !cont.contains(el)) return;
    var toIdx = parseInt(el.getAttribute('data-i'));
    if(toIdx === fromIdx) return;
    var cfg = DRAG_CONTAINERS[cid];
    if(!cfg || !cfg.arr) return;
    // Faire le déplacement sur le tableau D directement
    var arr = cfg.arr;
    var item = arr.splice(fromIdx, 1)[0];
    arr.splice(toIdx, 0, item);
    saveData();
    cfg.fn();
    // Forcer visible sur tous les éléments reveal re-créés dans ce conteneur
    var redrawnCont = document.getElementById(cid);
    if(redrawnCont) {
      redrawnCont.querySelectorAll('.reveal,.reveal-left,.reveal-right,.reveal-scale').forEach(function(el) {
        el.classList.add('visible');
      });
    }
    if(isAdmin) initAllDrags();
  });
}


