// Popup de sélection de langue au 1er chargement (mémorisé via localStorage)
function showLangPickerIfNeeded() {
  try {
    var saved = localStorage.getItem('portfolio_lang');
    if(saved) return; // déjà choisi
  } catch(e) { return; }
  var overlay = document.getElementById('lang-picker-overlay');
  if(!overlay) return;
  overlay.style.display = 'flex';
  // Bloquer le scroll en arrière-plan
  document.body.style.overflow = 'hidden';
  overlay.querySelectorAll('.lang-picker-btn').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var chosen = btn.getAttribute('data-lang') || 'fr';
      try { localStorage.setItem('portfolio_lang', chosen); } catch(e) {}
      overlay.style.display = 'none';
      document.body.style.overflow = '';
      setLang(chosen);
    });
  });
}
showLangPickerIfNeeded();

