import React, { useEffect, useState } from 'react';

/** Pied de page — copyright dynamique injecté via `renderContact()` + compteur de visiteurs. */
const Footer = () => {
  const [count, setCount] = useState(null);

  useEffect(() => {
    try {
      const isNewSession = !sessionStorage.getItem('portfolio_session');
      let n = parseInt(localStorage.getItem('portfolio_visits') || '0', 10) || 0;
      if (isNewSession) {
        n += 1;
        localStorage.setItem('portfolio_visits', String(n));
        sessionStorage.setItem('portfolio_session', '1');
      }
      setCount(n);
    } catch (e) {
      setCount(null);
    }
  }, []);

  return (
    <footer>
      <div className="footer-copy" id="footer-copy">© 2025 Afiavi Elisabeth DORKENOO — Tous droits réservés</div>
      <div className="footer-meta">
        {count !== null && (
          <span className="visitor-counter" data-testid="visitor-counter" title="Nombre de visites cumulées">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
              <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
              <circle cx="12" cy="12" r="3" />
            </svg>
            <span>{count.toLocaleString('fr-FR')}</span>
            <span className="visitor-counter-lbl" data-fr="visites" data-en="views">visites</span>
          </span>
        )}
        <span className="footer-made">
          Conçu &amp; développé par <span>AED</span>
        </span>
      </div>
    </footer>
  );
};

export default Footer;
